6. <h1>Weather</h1>
7. 
8. <p>This component demonstrates showing data.</p>
9. 
10. @if (forecasts == null)
11. {
12.     <p><em>Loading...</em></p>
13. }
14. else
15. {
16.     <table class="table">
17.         <thead>
18.             <tr>
