namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public decimal WeightKg { get; set; }
    public DateTime CreatedAtUtc { get; set; }
    public DateTime? EstimatedDeliveryUtc { get; set; }
    public DateTime? ActualDeliveryUtc { get; set; }
}

public class UpdateShipmentStatusRequest
{
    public string Status { get; set; } = string.Empty;
}

public static class ShipmentStatuses
{
    public const string Pending = "Pending";
    public const string PickedUp = "Picked Up";
    public const string InTransit = "In Transit";
    public const string OutForDelivery = "Out for Delivery";
    public const string Delivered = "Delivered";
    public const string Cancelled = "Cancelled";

    public static readonly string[] All =
    [
        Pending, PickedUp, InTransit, OutForDelivery, Delivered, Cancelled
    ];
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null);
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, string newStatus);
    Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto shipment);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentApiService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null)
    {
        var url = "/api/shipments";
        if (!string.IsNullOrWhiteSpace(statusFilter))
            url += $"?status={Uri.EscapeDataString(statusFilter)}";

        return await http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        try
        {
            return await http.GetFromJsonAsync<ShipmentDto>(
                $"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        }
        catch (HttpRequestException ex) when (ex.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            return null;
        }
    }

    public async Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, string newStatus)
    {
        var response = await http.PutAsJsonAsync(
            $"/api/shipments/{id}/status",
            new UpdateShipmentStatusRequest { Status = newStatus });
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }
}

