using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentApiService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null)
    {
        var url = "/api/shipments";
        if (!string.IsNullOrWhiteSpace(statusFilter))
            url += $"?status={Uri.EscapeDataString(statusFilter)}";

        return await http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        try
        {
            return await http.GetFromJsonAsync<ShipmentDto>(
                $"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        }
        catch (HttpRequestException ex) when (ex.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            return null;
        }
    }

    public async Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, string newStatus)
    {
        var response = await http.PutAsJsonAsync(
            $"/api/shipments/{id}/status",
            new UpdateShipmentStatusRequest { Status = newStatus });
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }
}

