using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null)
    {
        var query = db.Shipments.AsQueryable();
        if (!string.IsNullOrWhiteSpace(statusFilter))
            query = query.Where(s => s.Status == statusFilter);

        return await query
            .OrderByDescending(s => s.CreatedAtUtc)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, string newStatus)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return null;

        shipment.Status = newStatus;
        if (newStatus == ShipmentStatuses.Delivered)
            shipment.ActualDeliveryUtc = DateTime.UtcNow;

        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = ShipmentStatuses.Pending,
            CustomerEmail = dto.CustomerEmail,
            Description = dto.Description,
            WeightKg = dto.WeightKg,
            CreatedAtUtc = DateTime.UtcNow,
            EstimatedDeliveryUtc = DateTime.UtcNow.AddDays(Random.Shared.Next(3, 14))
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description,
        WeightKg = s.WeightKg,
        CreatedAtUtc = s.CreatedAtUtc,
        EstimatedDeliveryUtc = s.EstimatedDeliveryUtc,
        ActualDeliveryUtc = s.ActualDeliveryUtc
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}

