+
+namespace ShipmentTracker.Services;
+
+public class ShipmentService(ApplicationDbContext db) : IShipmentService
+{
+    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null)
+    {
+        var query = db.Shipments.AsQueryable();
+        if (!string.IsNullOrWhiteSpace(statusFilter))
+            query = query.Where(s => s.Status == statusFilter);
+
+        return await query
+            .OrderByDescending(s => s.CreatedAtUtc)
+            .Select(s => ToDto(s))
+            .ToListAsync();
+    }
+
+    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
+    {
+        var shipment = await db.Shipments
+            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
+        return shipment is null ? null : ToDto(shipment);
+    }
+
+    public async Task<ShipmentDto?> UpdateShipmentStatusAsync(int id, string newStatus)
+    {
+        var shipment = await db.Shipments.FindAsync(id);
+        if (shipment is null) return null;
+
+        shipment.Status = newStatus;
+        if (newStatus == ShipmentStatuses.Delivered)
+            shipment.ActualDeliveryUtc = DateTime.UtcNow;
