using Microsoft.AspNetCore.Authorization;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        group.MapGet("/", [Authorize] async (IShipmentService service, string? status) =>
        {
            var shipments = await service.GetAllShipmentsAsync(status);
            return Results.Ok(shipments);
        });

        group.MapGet("/track/{trackingNumber}", async (IShipmentService service, string trackingNumber) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapPut("/{id:int}/status", [Authorize] async (IShipmentService service, int id, UpdateShipmentStatusRequest request) =>
        {
            var shipment = await service.UpdateShipmentStatusAsync(id, request.Status);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapPost("/", [Authorize] async (IShipmentService service, ShipmentDto dto) =>
        {
            var created = await service.CreateShipmentAsync(dto);
            return Results.Created($"/api/shipments/track/{created!.TrackingNumber}", created);
        });
    }
}

