@page "/dispatcher"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>📦 Dispatcher Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="selectedStatus" @bind:after="LoadShipments">
            <option value="">All Statuses</option>
            @foreach (var status in ShipmentStatuses.All)
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-outline-primary" @onclick="LoadShipments">
            🔄 Refresh
        </button>
    </div>
    <div class="col-md-4 d-flex align-items-end justify-content-end">
        <button class="btn btn-success" @onclick="ToggleCreateForm">
            ➕ New Shipment
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="create-shipment">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="newShipment.WeightKg" />
                    </div>
                    <div class="col-12 mb-3">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="newShipment.Description" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary" disabled="@isCreating">
                    @(isCreating ? "Creating..." : "Create Shipment")
                </button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="ToggleCreateForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <div class="alert alert-info">No shipments found.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Weight</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in shipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.WeightKg kg</td>
                        <td>@(shipment.EstimatedDeliveryUtc?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="e => UpdateStatus(shipment, e.Value?.ToString()!)">
                                @foreach (var status in ShipmentStatuses.All)
                                {
                                    <option value="@status" selected="@(status == shipment.Status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(statusMessage))
{
    <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3">
        @statusMessage
        <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string selectedStatus = "";
    private bool showCreateForm;
    private bool isCreating;
    private ShipmentDto newShipment = new();
    private string? statusMessage;
    private bool isError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = null;
        var filter = string.IsNullOrWhiteSpace(selectedStatus) ? null : selectedStatus;
        shipments = await ShipmentService.GetAllShipmentsAsync(filter);
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        try
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                shipment.Status = updated.Status;
                shipment.ActualDeliveryUtc = updated.ActualDeliveryUtc;
                statusMessage = $"Shipment {shipment.TrackingNumber} updated to '{newStatus}'.";
                isError = false;
            }
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to update status: {ex.Message}";
            isError = true;
        }
    }

    private void ToggleCreateForm()
    {
        showCreateForm = !showCreateForm;
        if (showCreateForm)
            newShipment = new ShipmentDto();
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        try
        {
            var created = await ShipmentService.CreateShipmentAsync(newShipment);
            statusMessage = $"Shipment {created?.TrackingNumber} created successfully!";
            isError = false;
            showCreateForm = false;
            newShipment = new ShipmentDto();
            await LoadShipments();
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to create shipment: {ex.Message}";
            isError = true;
        }
        finally
        {
            isCreating = false;
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "Picked Up" => "bg-info text-dark",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@page "/track/{TrackingNumber}"
@rendermode InteractiveAuto

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>🔍 Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260501-10001)"
                   @bind="searchTrackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isSearching">
                @(isSearching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (hasSearched && shipment is null && !isSearching)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "<code>@lastSearched</code>".
        Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
            <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <h6>Route</h6>
                    <p>
                        <strong>From:</strong> @shipment.Origin<br />
                        <strong>To:</strong> @shipment.Destination
                    </p>
                </div>
                <div class="col-md-6">
                    <h6>Shipment Details</h6>
                    <p>
                        <strong>Description:</strong> @shipment.Description<br />
                        <strong>Weight:</strong> @shipment.WeightKg kg
                    </p>
                </div>
            </div>

            <hr />

            <div class="row">
                <div class="col-md-4">
                    <h6>Shipped On</h6>
                    <p>@shipment.CreatedAtUtc.ToString("MMMM dd, yyyy")</p>
                </div>
                <div class="col-md-4">
                    <h6>Estimated Delivery</h6>
                    @if (shipment.EstimatedDeliveryUtc.HasValue)
                    {
                        var daysLeft = (shipment.EstimatedDeliveryUtc.Value - DateTime.UtcNow).Days;
                        <p>
                            @shipment.EstimatedDeliveryUtc.Value.ToString("MMMM dd, yyyy")
                            @if (shipment.Status != ShipmentStatuses.Delivered && shipment.Status != ShipmentStatuses.Cancelled)
                            {
                                <br />
                                <small class="text-muted">
                                    @if (daysLeft > 0)
                                    {
                                        @($"({daysLeft} day{(daysLeft == 1 ? "" : "s")} remaining)")
                                    }
                                    else if (daysLeft == 0)
                                    {
                                        @("(Due today)")
                                    }
                                    else
                                    {
                                        @($"({Math.Abs(daysLeft)} day{(Math.Abs(daysLeft) == 1 ? "" : "s")} overdue)")
                                    }
                                </small>
                            }
                        </p>
                    }
                    else
                    {
                        <p class="text-muted">Not yet determined</p>
                    }
                </div>
                <div class="col-md-4">
                    <h6>Actual Delivery</h6>
                    <p>@(shipment.ActualDeliveryUtc?.ToString("MMMM dd, yyyy") ?? "—")</p>
                </div>
            </div>

            @* Progress visualization *@
            <div class="mt-4">
                <h6>Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(shipment.Status))%"
                         aria-valuenow="@GetProgressPercent(shipment.Status)"
                         aria-valuemin="0" aria-valuemax="100">
                        @shipment.Status
                    </div>
                </div>
                <div class="d-flex justify-content-between mt-1">
                    <small>Pending</small>
                    <small>Picked Up</small>
                    <small>In Transit</small>
                    <small>Out for Delivery</small>
                    <small>Delivered</small>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = "";
    private string? lastSearched;
    private ShipmentDto? shipment;
    private bool isSearching;
    private bool hasSearched;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrWhiteSpace(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await Search();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber))
            return;

        isSearching = true;
        hasSearched = true;
        lastSearched = searchTrackingNumber.Trim();
        shipment = null;

        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
        }
        finally
        {
            isSearching = false;
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "Picked Up" => "bg-info text-dark",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(string status) => status switch
    {
        "Cancelled" => "bg-danger",
        "Delivered" => "bg-success",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };

    private static int GetProgressPercent(string status) => status switch
    {
        "Pending" => 10,
        "Picked Up" => 30,
        "In Transit" => 55,
        "Out for Delivery" => 80,
        "Delivered" => 100,
        "Cancelled" => 100,
        _ => 0
    };
}

