toolArgs.file_text:
@page "/track"
@page "/track/{TrackingNumber}"
@rendermode InteractiveAuto

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>🔍 Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260501-10001)"
                   @bind="searchTrackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isSearching">
                @(isSearching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (hasSearched && shipment is null && !isSearching)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "<code>@lastSearched</code>".
        Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
            <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <h6>Route</h6>
                    <p>
                        <strong>From:</strong> @shipment.Origin<br />
                        <strong>To:</strong> @shipment.Destination
                    </p>
                </div>
                <div class="col-md-6">
                    <h6>Shipment Details</h6>
                    <p>
                        <strong>Description:</strong> @shipment.Description<br />
                        <strong>Weight:</strong> @shipment.WeightKg kg
                    </p>
                </div>
            </div>

            <hr />

            <div class="row">
                <div class="col-md-4">
                    <h6>Shipped On</h6>
                    <p>@shipment.CreatedAtUtc.ToString("MMMM dd, yyyy")</p>
                </div>
                <div class="col-md-4">
                    <h6>Estimated Delivery</h6>
                    @if (shipment.EstimatedDeliveryUtc.HasValue)
                    {
                        var daysLeft = (shipment.EstimatedDeliveryUtc.Value - DateTime.UtcNow).Days;
                        <p>
                            @shipment.EstimatedDeliveryUtc.Value.ToString("MMMM dd, yyyy")
                            @if (shipment.Status != ShipmentStatuses.Delivered && shipment.Status != ShipmentStatuses.Cancelled)
                            {
                                <br />
                                <small class="text-muted">
                                    @if (daysLeft > 0)
                                    {
                                        @($"({daysLeft} day{(daysLeft == 1 ? "" : "s")} remaining)")
                                    }
                                    else if (daysLeft == 0)
                                    {
                                        @("(Due today)")
                                    }
                                    else
                                    {
                                        @($"({Math.Abs(daysLeft)} day{(Math.Abs(daysLeft) == 1 ? "" : "s")} overdue)")
                                    }
                                </small>
                            }
                        </p>
                    }
                    else
                    {
                        <p class="text-muted">Not yet determined</p>
                    }
                </div>
                <div class="col-md-4">
                    <h6>Actual Delivery</h6>
                    <p>@(shipment.ActualDeliveryUtc?.ToString("MMMM dd, yyyy") ?? "—")</p>
                </div>
            </div>

            @* Progress visualization *@
            <div class="mt-4">
                <h6>Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(shipment.Status))%"
                         aria-valuenow="@GetProgressPercent(shipment.Status)"
                         aria-valuemin="0" aria-valuemax="100">
                        @shipment.Status
                    </div>
                </div>
                <div class="d-flex justify-content-between mt-1">
                    <small>Pending</small>
                    <small>Picked Up</small>
                    <small>In Transit</small>
                    <small>Out for Delivery</small>
                    <small>Delivered</small>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = "";
    private string? lastSearched;
    private ShipmentDto? shipment;
    private bool isSearching;
    private bool hasSearched;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrWhiteSpace(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await Search();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber))
            return;

        isSearching = true;
        hasSearched = true;
        lastSearched = searchTrackingNumber.Trim();
        shipment = null;

        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
        }
        finally
        {
            isSearching = false;
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "Picked Up" => "bg-info text-dark",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(string status) => status switch
    {
        "Cancelled" => "bg-danger",
        "Delivered" => "bg-success",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };

    private static int GetProgressPercent(string status) => status switch
    {
        "Pending" => 10,
        "Picked Up" => 30,
        "In Transit" => 55,
        "Out for Delivery" => 80,
        "Delivered" => 100,
        "Cancelled" => 100,
        _ => 0
    };
}
